from typing import List

def is_palindrome(num: int) -> bool:
    return str(num) == str(num)[::-1]

def count_digits(num: int) -> List[int]:
    return [str(num).count(str(d)) for d in range(10)]

def is_special(num: int) -> bool:
    digits = count_digits(num)
    for i in range(10):
        if digits[i] != i:
            return False
    return True

def solve(n: int) -> int:
    if n == 0:
        return 1
    while True:
        n += 1
        if is_palindrome(n) and is_special(n):
            return n
